pub fn lookup(name: &str) -> Option<&'static [(u32, u32)]> {
    match name {
        "Changes_When_Uppercased" => Some(BIN_CHANGES_WHEN_UPPERCASED),
        "Dash" => Some(BIN_DASH),
        "Default_Ignorable_Code_Point" => Some(BIN_DEFAULT_IGNORABLE_CODE_POINT),
        "Deprecated" => Some(BIN_DEPRECATED),
        "Diacritic" => Some(BIN_DIACRITIC),
        "Emoji" => Some(BIN_EMOJI),
        "Emoji_Component" => Some(BIN_EMOJI_COMPONENT),
        "Emoji_Modifier" => Some(BIN_EMOJI_MODIFIER),
        "Emoji_Modifier_Base" => Some(BIN_EMOJI_MODIFIER_BASE),
        "Emoji_Presentation" => Some(BIN_EMOJI_PRESENTATION),
        "Extended_Pictographic" => Some(BIN_EXTENDED_PICTOGRAPHIC),
        "Extender" => Some(BIN_EXTENDER),
        "Grapheme_Base" => Some(BIN_GRAPHEME_BASE),
        "Grapheme_Extend" => Some(BIN_GRAPHEME_EXTEND),
        "Hex_Digit" => Some(BIN_HEX_DIGIT),
        "IDS_Binary_Operator" => Some(BIN_IDS_BINARY_OPERATOR),
        "IDS_Trinary_Operator" => Some(BIN_IDS_TRINARY_OPERATOR),
        "ID_Continue" => Some(BIN_ID_CONTINUE),
        "ID_Start" => Some(BIN_ID_START),
        "Ideographic" => Some(BIN_IDEOGRAPHIC),
        "Join_Control" => Some(BIN_JOIN_CONTROL),
        "Logical_Order_Exception" => Some(BIN_LOGICAL_ORDER_EXCEPTION),
        "Lowercase" => Some(BIN_LOWERCASE),
        _ => None,
    }
}
